15	//! Clipboard harvest — capture every arboard-accessible clipboard flavor
16	//! verbatim to `{N}.{ext}` files in the journal directory (typically
17	//! `$HOME/apcjd/`) on the Clinical branch, before the system-clipboard
18	//! zero-out. PHI-at-rest stays outside the repo; anonymization and
19	//! promotion to test fixtures are manual. The destination is supplied by
20	//! the caller; see `apcrj_journal::apcrj_journal_path`. This module does
21	//! not emit — errors are returned to the caller for routing via `apcrl_*`.
22	
23	use std::fs;
24	use std::io::Write;
25	use std::path::Path;
26	
27	pub const APCRH_HARVEST_SEED_INDEX: u32 = 10000;
28	
29	/// Capture every arboard-accessible clipboard flavor into `{N}.{ext}` files
30	/// in `dir`. Returns the N used. N seeds at `APCRH_HARVEST_SEED_INDEX` when
31	/// `dir` is empty, otherwise `max_existing_numeric_stem + 1`. The directory
32	/// is created lazily. Text is required; HTML is opportunistic — absence of
33	/// HTML on the clipboard is not an error.
34	pub fn apcrh_capture_all_flavors(dir: &Path) -> Result<u32, String> {
35	    fs::create_dir_all(dir)
36	        .map_err(|e| format!("create harvest dir {}: {}", dir.display(), e))?;
37	
38	    let index = zapcrh_scan_next_index(dir)?;
39	
40	    let mut clipboard = arboard::Clipboard::new()
41	        .map_err(|e| format!("clipboard open: {}", e))?;
42	
43	    let text = clipboard.get_text()
44	        .map_err(|e| format!("clipboard get_text: {}", e))?;
45	    zapcrh_write_text(dir, index, &text)?;
46	
47	    // HTML is opportunistic — absence on the clipboard is expected for some
48	    // sources, not an error. Capture when present, skip otherwise.
49	    if let Ok(html) = clipboard.get().html() {
50	        zapcrh_write_html(dir, index, &html)?;
51	    }
52	
53	    Ok(index)
54	}
55	
56	/// Scan `dir` for numeric file stems and return `max+1`, or
57	/// `APCRH_HARVEST_SEED_INDEX` when none are found. Non-numeric stems and
58	/// subdirectories are ignored. Gaps are not filled — the scan advances past
59	/// the current maximum.
60	pub(crate) fn zapcrh_scan_next_index(dir: &Path) -> Result<u32, String> {
61	    let entries = fs::read_dir(dir)
62	        .map_err(|e| format!("read harvest dir {}: {}", dir.display(), e))?;
63	
64	    let mut max: Option<u32> = None;
65	    for entry in entries {
66	        let entry = entry
67	            .map_err(|e| format!("read harvest entry: {}", e))?;
68	        if !entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
69	            continue;
70	        }
71	        let path = entry.path();
72	        let stem = match path.file_stem().and_then(|s| s.to_str()) {
73	            Some(s) => s,
74	            None    => continue,
75	        };
76	        if let Ok(n) = stem.parse::<u32>() {
77	            max = Some(max.map_or(n, |m| m.max(n)));
78	        }
79	    }
80	
81	    Ok(match max {
82	        Some(n) => n.saturating_add(1),
83	        None    => APCRH_HARVEST_SEED_INDEX,
84	    })
85	}
86	
87	/// Write the text flavor to `{index}.txt` in `dir`.
88	pub(crate) fn zapcrh_write_text(dir: &Path, index: u32, text: &str) -> Result<(), String> {
89	    let path = dir.join(format!("{}.txt", index));
90	    let mut file = fs::File::create(&path)
91	        .map_err(|e| format!("create {}: {}", path.display(), e))?;
92	    file.write_all(text.as_bytes())
93	        .map_err(|e| format!("write {}: {}", path.display(), e))?;
94	    Ok(())
95	}
96	
97	/// Write the HTML flavor to `{index}.html` in `dir`.
98	pub(crate) fn zapcrh_write_html(dir: &Path, index: u32, html: &str) -> Result<(), String> {
99	    let path = dir.join(format!("{}.html", index));
100	    let mut file = fs::File::create(&path)
101	        .map_err(|e| format!("create {}: {}", path.display(), e))?;
102	    file.write_all(html.as_bytes())
103	        .map_err(|e| format!("write {}: {}", path.display(), e))?;
104	    Ok(())
105	}
