15	//! Tests for clipboard harvest scan/write helpers. Full-capture tests are
16	//! out of scope here — the clipboard is a global resource and arboard cannot
17	//! be exercised reliably under parallel `cargo test`.
18	
19	use super::apcrh_harvest::*;
20	use std::fs;
21	use std::path::PathBuf;
22	use std::sync::atomic::{AtomicU64, Ordering};
