26	struct zapcth_TempDir {
27	    path: PathBuf,
28	}
29	
30	impl zapcth_TempDir {
31	    fn zapcth_new(tag: &str) -> Self {
32	        let nonce = ZAPCTH_NONCE.fetch_add(1, Ordering::SeqCst);
33	        let nanos = std::time::SystemTime::now()
34	            .duration_since(std::time::UNIX_EPOCH)
35	            .unwrap()
36	            .as_nanos();
37	        let mut path = std::env::temp_dir();
38	        path.push(format!("apcth_{}_{}_{}_{}", tag, std::process::id(), nanos, nonce));
39	        fs::create_dir_all(&path).unwrap();
40	        zapcth_TempDir { path }
41	    }
42	}
43	
44	impl Drop for zapcth_TempDir {
45	    fn drop(&mut self) {
46	        let _ = fs::remove_dir_all(&self.path);
47	    }
48	}
