50	#[test]
51	fn apcth_scan_empty_dir_returns_seed() {
52	    let td = zapcth_TempDir::zapcth_new("empty");
53	    let next = zapcrh_scan_next_index(&td.path).unwrap();
54	    assert_eq!(next, APCRH_HARVEST_SEED_INDEX);
55	}
56	
57	#[test]
58	fn apcth_scan_same_index_group_counts_once() {
59	    let td = zapcth_TempDir::zapcth_new("group");
60	    fs::write(td.path.join("10000.html"), "<html/>").unwrap();
61	    fs::write(td.path.join("10000.txt"),  "text").unwrap();
62	    let next = zapcrh_scan_next_index(&td.path).unwrap();
63	    assert_eq!(next, 10001);
