66	#[test]
67	fn apcth_scan_ignores_non_numeric_stems() {
68	    let td = zapcth_TempDir::zapcth_new("alpha");
69	    fs::write(td.path.join("README.md"),     "docs").unwrap();
70	    fs::write(td.path.join("notes.txt"),     "notes").unwrap();
71	    fs::write(td.path.join("10005.txt"),     "five").unwrap();
72	    fs::write(td.path.join("garbage.html"),  "<p/>").unwrap();
73	    let next = zapcrh_scan_next_index(&td.path).unwrap();
74	    assert_eq!(next, 10006);
75	}
76	
77	#[test]
78	fn apcth_scan_gaps_do_not_fill() {
79	    let td = zapcth_TempDir::zapcth_new("gaps");
80	    fs::write(td.path.join("10000.txt"), "a").unwrap();
81	    fs::write(td.path.join("10003.txt"), "b").unwrap();
82	    fs::write(td.path.join("10007.txt"), "c").unwrap();
83	    let next = zapcrh_scan_next_index(&td.path).unwrap();
