220	        }
221	
222	        if finding.offset > pos {
223	            result.push_str(&plain_text[pos..finding.offset]);
224	        }
225	
226	        let state = toggle_states.get(*idx).map(|s| s.as_str()).unwrap_or("elide");
227	        if state == "pass" {
228	            result.push_str(&plain_text[finding.offset..finding.offset + finding.length]);
229	        } else {
230	            result.push_str(&finding.replacement);
231	        }
232	
233	        pos = finding.offset + finding.length;
234	    }
235	
236	    if pos < plain_text.len() {
237	        result.push_str(&plain_text[pos..]);
