28	
29	static ZAPCAP_DICTS: OnceLock<apcd::apcrd_dictionaries::apcrd_Dictionaries> = OnceLock::new();
30	static ZAPCAP_LAST_CLIPBOARD: Mutex<Option<String>> = Mutex::new(None);
31	static ZAPCAP_LAST_CLINICAL: Mutex<Option<zapcap_ClinicalCache>> = Mutex::new(None);
32	static ZAPCAP_TOGGLE_STATES: Mutex<Vec<String>> = Mutex::new(Vec::new());
33	
34	struct zapcap_ClinicalCache {
35	    findings:   Vec<apcrm_Finding>,
36	    plain_text: String,
37	}
38	
39	// ---------------------------------------------------------------------------
40	// Focus handler — read clipboard, run detection, push rendered HTML
41	// ---------------------------------------------------------------------------
42	
43	fn zapcap_handle_focus(window: &tauri::WebviewWindow) -> Result<(), String> {
44	    let mut clipboard = arboard::Clipboard::new()
45	        .map_err(|e| format!("clipboard error: {}", e))?;
46	
47	    let content = clipboard.get_text()
48	        .map_err(|e| format!("clipboard error: {}", e))?;
49	
50	    apcd::apcrl_info_now!("focus: {} bytes", content.len());
51	
52	    // Change detection — same content as last invocation → preserve UI state
53	    {
54	        let last = ZAPCAP_LAST_CLIPBOARD.lock()
55	            .map_err(|e| format!("lock error: {}", e))?;
56	        if last.as_deref() == Some(content.as_str()) {
57	            apcd::apcrl_info_now!("focus: unchanged");
58	            return Ok(());
59	        }
60	    }
61	
62	    let dicts = ZAPCAP_DICTS.get_or_init(apcd::apcrd_dictionaries::apcrd_Dictionaries::apcrd_load);
63	
64	    match apcd::apcre_engine::apcre_analyze(&content, dicts) {
65	        apcd::apcre_engine::apcre_Result::Clinical { findings, plain_text } => {
66	            apcd::apcrl_info_now!("clinical: {} findings", findings.len());
67	            // Harvest every arboard-accessible flavor before the clipboard
68	            // zero-out. Success and failure both log — the journal log is
69	            // a confirmation mechanism, not just an error record.
70	            match apcd::apcrj_journal::apcrj_journal_path() {
71	                Some(journal_dir) => {
72	                    match apcd::apcrh_harvest::apcrh_capture_all_flavors(&journal_dir) {
73	                        Ok(n)  => apcd::apcrl_info_now!("harvest captured as {}", n),
74	                        Err(e) => apcd::apcrl_error_now!("harvest capture failed: {}", e),
75	                    }
76	                }
77	                None => {
78	                    apcd::apcrl_error_now!("harvest skipped: HOME not set");
79	                }
80	            }
81	
82	            // Clear system clipboard after consuming clinical content
83	            let _ = clipboard.set_text(String::new());
84	
85	            {
86	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
87	                    .map_err(|e| format!("lock error: {}", e))?;
88	                *last = Some(String::new());
89	            }
90	
91	            {
92	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
93	                    .map_err(|e| format!("lock error: {}", e))?;
94	                *toggle_states = vec!["elide".to_string(); findings.len()];
95	            }
96	
97	            {
98	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
99	                    .map_err(|e| format!("lock error: {}", e))?;
100	                *cache = Some(zapcap_ClinicalCache { findings, plain_text });
101	            }
102	
103	            zapcap_push_triage(window)
104	        }
105	        apcd::apcre_engine::apcre_Result::NonClinical { content_length, content_type, preview } => {
106	            apcd::apcrl_info_now!("non-clinical: {} ({} bytes)", content_type, content_length);
107	            {
108	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
109	                    .map_err(|e| format!("lock error: {}", e))?;
110	                *last = Some(content);
111	            }
112	
113	            {
114	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
115	                    .map_err(|e| format!("lock error: {}", e))?;
116	                *cache = None;
117	            }
118	
119	            {
120	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
121	                    .map_err(|e| format!("lock error: {}", e))?;
122	                *toggle_states = Vec::new();
123	            }
124	
125	            let diagnostic = format!(
126	                "Not clinical ({} bytes, {}): {}",
127	                content_length, content_type, preview
128	            );
129	            zapcap_push_instruction(window, &diagnostic)
130	        }
131	    }
132	}
133	
134	// ---------------------------------------------------------------------------
135	// Tauri commands — toggle finding, copy anonymized
136	// ---------------------------------------------------------------------------
137	
138	#[tauri::command]
139	fn toggle_finding(index: usize, window: tauri::WebviewWindow) -> Result<(), String> {
140	    {
141	        let mut states = ZAPCAP_TOGGLE_STATES.lock()
142	            .map_err(|e| format!("lock error: {}", e))?;
143	        if index < states.len() {
144	            states[index] = if states[index] == "elide" {
145	                "pass".to_string()
146	            } else {
147	                "elide".to_string()
148	            };
149	        }
150	    }
151	    zapcap_push_triage(&window)
152	}
153	
154	#[tauri::command]
155	fn copy_anonymized(window: tauri::WebviewWindow) -> Result<(), String> {
156	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
157	        .map_err(|e| format!("lock error: {}", e))?
158	        .clone();
159	
160	    let anonymized = {
161	        let cache = ZAPCAP_LAST_CLINICAL.lock()
162	            .map_err(|e| format!("lock error: {}", e))?;
163	        let clinical = cache.as_ref()
164	            .ok_or_else(|| "no clinical data to anonymize".to_string())?;
165	        apcd::apcre_engine::apcre_anonymize(
166	            &clinical.plain_text,
167	            &clinical.findings,
168	            &toggle_states,
169	        )
170	    };
171	
172	    let mut clipboard = arboard::Clipboard::new()
173	        .map_err(|e| format!("clipboard error: {}", e))?;
174	    clipboard.set_text(anonymized)
175	        .map_err(|e| format!("clipboard error: {}", e))?;
176	
177	    zapcap_push_triage_with_feedback(&window, "Copied!")?;
178	
179	    let win = window.clone();
180	    std::thread::spawn(move || {
181	        std::thread::sleep(std::time::Duration::from_secs(2));
182	        let _ = zapcap_push_triage(&win);
183	    });
184	
185	    Ok(())
186	}
187	
188	// ---------------------------------------------------------------------------
189	// HTML push — render state and inject into webview
190	// ---------------------------------------------------------------------------
191	
192	fn zapcap_push_instruction(window: &tauri::WebviewWindow, diagnostic: &str) -> Result<(), String> {
193	    let html = zapcap_render_instruction(diagnostic);
194	    zapcap_eval_html(window, &html)
195	}
196	
197	fn zapcap_push_triage(window: &tauri::WebviewWindow) -> Result<(), String> {
198	    zapcap_push_triage_with_feedback(window, "Copy Anonymized to Clipboard")
199	}
200	
201	fn zapcap_push_triage_with_feedback(
202	    window: &tauri::WebviewWindow,
203	    btn_text: &str,
204	) -> Result<(), String> {
205	    // Clone data out of locks to avoid holding multiple locks simultaneously
206	    let (findings, plain_text) = {
207	        let cache = ZAPCAP_LAST_CLINICAL.lock()
208	            .map_err(|e| format!("lock error: {}", e))?;
209	        let clinical = cache.as_ref()
210	            .ok_or_else(|| "no clinical data for triage".to_string())?;
211	        (clinical.findings.clone(), clinical.plain_text.clone())
