227	// ---------------------------------------------------------------------------
228	// HTML rendering — instruction state
229	// ---------------------------------------------------------------------------
230	
231	fn zapcap_render_instruction(diagnostic: &str) -> String {
232	    format!(
233	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
234	         <p class=\"instruction\">Copy a clinical note from Epic using \
235	         &ldquo;Copy All&rdquo;, then switch to this window.</p>\
236	         <p class=\"diagnostic\">{}</p>",
237	        zapcap_escape_html(diagnostic)
238	    )
239	}
240	
241	// ---------------------------------------------------------------------------
242	// HTML rendering — triage state
243	// ---------------------------------------------------------------------------
244	
245	fn zapcap_render_triage(
246	    findings: &[apcrm_Finding],
247	    plain_text: &str,
248	    toggle_states: &[String],
249	    btn_text: &str,
250	) -> String {
251	    let preview = zapcap_render_preview(findings, plain_text, toggle_states);
252	    let (yellow_html, red_html) = zapcap_render_findings(findings, toggle_states);
253	
254	    format!(
255	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
256	         <div id=\"document-preview\">{}</div>\
257	         <div id=\"findings-panel\">\
258	         <div class=\"findings-section\" id=\"findings-yellow\">\
259	         <h3>Questionable Findings</h3>\
260	         <div class=\"findings-list\" id=\"yellow-list\">{}</div></div>\
261	         <div class=\"findings-section\" id=\"findings-red\">\
262	         <h3>Definite PHI</h3>\
263	         <div class=\"findings-list\" id=\"red-list\">{}</div></div></div>\
264	         <button id=\"copy-btn\" \
265	         onclick=\"window.__TAURI__.core.invoke('copy_anonymized')\">{}</button>",
266	        preview, yellow_html, red_html, zapcap_escape_html(btn_text)
267	    )
268	}
269	
270	// ---------------------------------------------------------------------------
271	// HTML rendering — document preview with inline PHI highlights
272	// ---------------------------------------------------------------------------
273	
274	fn zapcap_render_preview(
275	    findings: &[apcrm_Finding],
276	    plain_text: &str,
277	    toggle_states: &[String],
278	) -> String {
279	    // Build index-annotated list sorted by offset (byte offsets used directly)
280	    let mut sorted: Vec<(usize, &apcrm_Finding)> = findings.iter().enumerate().collect();
281	    sorted.sort_by(|a, b| a.1.offset.cmp(&b.1.offset).then(b.1.length.cmp(&a.1.length)));
282	
283	    let mut parts = Vec::new();
284	    let mut pos: usize = 0;
285	
286	    for (idx, f) in &sorted {
287	        if f.offset < pos { continue; } // skip overlap
288	
289	        // Text before this finding
290	        if f.offset > pos {
291	            parts.push(zapcap_escape_html(&plain_text[pos..f.offset]));
292	        }
293	
294	        // Finding span — byte offsets consumed directly, no conversion needed
295	        let end = f.offset + f.length;
296	        let cls = if toggle_states.get(*idx).map(|s| s.as_str()) == Some("pass") {
297	            "phi-pass"
298	        } else if f.severity == apcrm_Severity::Red {
299	            "phi-red"
300	        } else {
301	            "phi-yellow"
302	        };
303	
304	        parts.push(format!(
305	            "<span class=\"{}\" data-index=\"{}\">{}</span>",
306	            cls, idx, zapcap_escape_html(&plain_text[f.offset..end])
307	        ));
308	        pos = end;
309	    }
310	
311	    // Remaining text
312	    if pos < plain_text.len() {
313	        parts.push(zapcap_escape_html(&plain_text[pos..]));
314	    }
315	
316	    parts.join("")
317	}
318	
319	// ---------------------------------------------------------------------------
320	// HTML rendering — findings panel (yellow + red sections)
321	// ---------------------------------------------------------------------------
322	
323	fn zapcap_render_findings(
324	    findings: &[apcrm_Finding],
325	    toggle_states: &[String],
326	) -> (String, String) {
327	    let mut yellow = Vec::new();
328	    let mut red = Vec::new();
329	
330	    for (i, f) in findings.iter().enumerate() {
331	        let state = toggle_states.get(i).map(|s| s.as_str()).unwrap_or("elide");
332	        let label = zapcap_format_category(f.category);
333	        let btn_text = if state == "elide" { "ELIDE \u{25bc}" } else { "PASS \u{25bc}" };
334	
335	        let entry = format!(
336	            "<div class=\"finding-entry\">\
337	             <span class=\"finding-text\">{}</span>\
338	             <span class=\"finding-category\">{}</span>\
339	             <button class=\"finding-toggle {}\" \
340	             onclick=\"window.__TAURI__.core.invoke('toggle_finding',{{index:{}}})\"\
341	             >{}</button></div>",
342	            zapcap_escape_html(&f.text),
343	            label,
344	            state,
345	            i,
346	            btn_text
347	        );
348	
349	        if f.severity == apcrm_Severity::Yellow {
350	            yellow.push(entry);
351	        } else {
352	            red.push(entry);
353	        }
354	    }
355	
356	    let yellow_html = if yellow.is_empty() {
357	        "<div class=\"empty-section\">None detected</div>".to_string()
358	    } else {
359	        yellow.join("")
360	    };
361	
362	    let red_html = if red.is_empty() {
363	        "<div class=\"empty-section\">None detected</div>".to_string()
364	    } else {
365	        red.join("")
366	    };
367	
368	    (yellow_html, red_html)
369	}
370	
371	// ---------------------------------------------------------------------------
372	// Utilities
373	// ---------------------------------------------------------------------------
374	
375	fn zapcap_format_category(cat: apcrm_PhiCategory) -> &'static str {
376	    match cat {
377	        apcrm_PhiCategory::Name         => "NAME",
378	        apcrm_PhiCategory::Provider     => "PROVIDER",
379	        apcrm_PhiCategory::Facility     => "FACILITY",
380	        apcrm_PhiCategory::Date         => "DATE",
381	        apcrm_PhiCategory::Dob          => "DOB",
382	        apcrm_PhiCategory::Phone        => "PHONE",
383	        apcrm_PhiCategory::Email        => "EMAIL",
